 4→export interface PluginOptions<T, C> {
 5→  executionsCountLimit?: number;
 6→  returnOnFirst?: boolean;
 7→}
 8→
 9→export interface PluginRegisterInfo<T, C> {
10→  name: string;
11→  existing: (SyncPluginMiddleware<T, C> | AsyncPluginMiddleware<T, C>)[];
12→}
13→
14→export interface PluginExecutionContext<T, C> {
15→  index: number;
16→  ignoredCount: number; // how many listeners called ignore()
17→  handledCount: number; // how many listeners updated values
18→  existing: (SyncPluginMiddleware<T, C> | AsyncPluginMiddleware<T, C>)[];
19→
20→  /**
21→   * True if any middleware called finish() or all middlewares have executed
22→   */
23→  finished: boolean;
24→  finishedValue: T | EmptySymbol;
25→  finishedError: Error | null;
26→
27→  error: Error | null;
28→
29→  /**
30→   * Stop queue execution and return the informed value in the parent execution
31→   * @param result
32→   */
33→  finish: (result: T) => void;
34→
35→  IgnoredSymbol: EmptySymbol;
36→
37→  /**
38→   * Exit current middleware execution and go to the next
39→   */
40→  exit(): EmptySymbol;
41→
42→  /**
43→   * Exit current middleware execution and go to the next
44→   */
45→  replace(value: T): void;
46→}
