 13→export const tupleEnum = <T extends string[]>(
 14→  ...values: T
 15→): {
 16→  readonly //
 17→  [K in T[number]]: K;
 18→} & (T[number] extends 'list' //
 19→  ? {
 20→      //
 21→      __list: T[number][];
 22→    }
 23→  : {
 24→      //
 25→      list: T[number][];
 26→    }) &
 27→  (T[number] extends 'enum'
 28→    ? {
 29→        //
 30→        __enum: T[number];
 31→      }
 32→    : {
 33→        //
 34→        enum: T[number];
 35→      }) => {
 36→  const en = values.reduce((p, n) => {
 37→    return {
 38→      ...p,
 39→      [n]: n,
 40→    };
 41→  }, Object.create(null));
 42→
 43→  Object.defineProperty(en, en.list !== undefined ? '__list' : 'list', {
 44→    enumerable: false,
 45→    value: values,
 46→  });
 47→
 48→  Object.defineProperty(en, en.enum !== undefined ? '__enum' : 'enum', {
 49→    enumerable: false,
 50→    get() {
 51→      return values[0];
 52→    },
 53→  });
 54→
 55→  return en;
 56→};
